using sv_0b9aaf9f1f184c6996a93d519b81399d.Models;

namespace sv_0b9aaf9f1f184c6996a93d519b81399d.Services;

public interface IRecipeService
{
    Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken);
}

using sv_0b9aaf9f1f184c6996a93d519b81399d.Models;

namespace sv_0b9aaf9f1f184c6996a93d519b81399d.Services;

public sealed class RecipeService : IRecipeService
{
    private static readonly Dictionary<int, List<Recipe>> SeedData = new()
    {
        [1] = new List<Recipe>
        {
            new(1, "Margherita Pizza", "Classic Neapolitan pizza with fresh mozzarella, basil, and San Marzano tomato sauce.", 30),
            new(2, "Spaghetti Carbonara", "Creamy Roman pasta with guanciale, egg yolk, Pecorino Romano, and black pepper.", 25),
            new(3, "Risotto alla Milanese", "Slow-cooked Arborio rice with saffron, Parmigiano-Reggiano, and butter.", 45),
        },
        [2] = new List<Recipe>
        {
            new(4, "Chicken Tikka Masala", "Tender chicken pieces in a rich, spiced tomato-cream sauce.", 50),
            new(5, "Palak Paneer", "Fresh paneer cubes simmered in a creamy spinach and spice gravy.", 40),
            new(6, "Biryani", "Fragrant basmati rice layered with marinated meat, saffron, and caramelized onions.", 60),
        },
        [3] = new List<Recipe>
        {
            new(7, "Tacos al Pastor", "Marinated pork with pineapple, cilantro, and onion on corn tortillas.", 35),
            new(8, "Chicken Enchiladas", "Corn tortillas filled with shredded chicken, topped with salsa verde and cheese.", 45),
            new(9, "Guacamole", "Fresh avocado mashed with lime juice, cilantro, jalapeño, and tomato.", 10),
        },
    };

    public async Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken)
    {
        await Task.Delay(2000, cancellationToken);

        return SeedData.TryGetValue(cuisineId, out var recipes)
            ? recipes
            : [];
    }
}

@page "/recipes/{CuisineId:int}"
@rendermode InteractiveServer
@implements IDisposable
@inject IRecipeService RecipeService
@inject NavigationManager Nav
@inject ILogger<Recipes> Logger

@using sv_0b9aaf9f1f184c6996a93d519b81399d.Models
@using sv_0b9aaf9f1f184c6996a93d519b81399d.Services

<PageTitle>Recipes</PageTitle>

<h1>Recipes — Cuisine @CuisineId</h1>

@if (_errorMessage is not null)
{
    <div class="alert alert-danger d-flex justify-content-between align-items-center" role="alert">
        <span>@_errorMessage</span>
        <button class="btn btn-outline-danger btn-sm" @onclick="RetryAsync">Retry</button>
    </div>
}

@if (_recipes is null && _isLoading)
{
    <div class="d-flex align-items-center gap-2 my-4">
        <div class="spinner-border spinner-border-sm" role="status"></div>
        <span>Loading recipes…</span>
    </div>
}
else if (_recipes is not null)
{
    @if (_isLoading)
    {
        <div class="d-flex align-items-center gap-2 mb-3">
            <div class="spinner-border spinner-border-sm" role="status"></div>
            <small class="text-muted">Refreshing…</small>
        </div>
    }

    <div class="mb-3">
        <label class="form-label fw-semibold">Sort by:</label>
        <a href="@GetSortUrl("newest")" class="btn btn-sm @(_sort == "newest" ? "btn-primary" : "btn-outline-primary") me-1">Newest</a>
        <a href="@GetSortUrl("popular")" class="btn btn-sm @(_sort == "popular" ? "btn-primary" : "btn-outline-primary")">Popular</a>
    </div>

    @if (_displayedRecipes.Count == 0)
    {
        <p class="text-muted">No recipes found for this cuisine.</p>
    }
    else
    {
        <div class="row row-cols-1 row-cols-md-3 g-4">
            @foreach (var recipe in _displayedRecipes)
            {
                <div class="col">
                    <div class="card h-100">
                        <div class="card-body">
                            <h5 class="card-title">@recipe.Title</h5>
                            <p class="card-text">@recipe.Description</p>
                        </div>
                        <div class="card-footer text-muted">
                            <small>Prep time: @recipe.PrepTimeMinutes min</small>
                        </div>
                    </div>
                </div>
            }
        </div>
    }
}

@code {
    [Parameter] public int CuisineId { get; set; }

    [SupplyParameterFromQuery(Name = "sort")]
    public string? Sort { get; set; }

    private List<Recipe>? _recipes;
    private List<Recipe> _displayedRecipes = [];
    private bool _isLoading;
    private string? _errorMessage;
    private string _sort = "newest";

    private int _loadedCuisineId;
    private CancellationTokenSource? _loadCts;

    protected override async Task OnParametersSetAsync()
    {
        var sort = string.Equals(Sort, "popular", StringComparison.OrdinalIgnoreCase) ? "popular" : "newest";

        if (_loadedCuisineId == CuisineId && _recipes is not null)
        {
            // Cuisine unchanged — only re-sort if needed.
            if (_sort != sort)
            {
                _sort = sort;
                _displayedRecipes = ApplySort(_recipes, _sort);
            }
            return;
        }

        _sort = sort;
        await LoadRecipesAsync(CuisineId);
    }

    private async Task LoadRecipesAsync(int cuisineId)
    {
        // Cancel any in-flight load.
        await CancelPendingLoadAsync();

        var cts = new CancellationTokenSource();
        _loadCts = cts;

        _isLoading = true;
        _errorMessage = null;
        StateHasChanged();

        try
        {
            var result = await RecipeService.GetByCuisineAsync(cuisineId, cts.Token);

            // Guard against a stale completion after cancellation.
            if (cts.Token.IsCancellationRequested) return;

            _recipes = result;
            _displayedRecipes = ApplySort(result, _sort);
            _loadedCuisineId = cuisineId;
            _errorMessage = null;
        }
        catch (OperationCanceledException) when (cts.Token.IsCancellationRequested)
        {
            // Expected when the user switched cuisines or navigated away.
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading recipes for cuisine {CuisineId}", cuisineId);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Failed to load recipes for cuisine {CuisineId}", cuisineId);
            _errorMessage = "Something went wrong while loading recipes. Please try again.";
        }
        finally
        {
            if (!cts.Token.IsCancellationRequested)
            {
                _isLoading = false;
            }
        }
    }

    private async Task RetryAsync()
    {
        await LoadRecipesAsync(CuisineId);
    }

    private static List<Recipe> ApplySort(List<Recipe> recipes, string sort)
    {
        return sort == "popular"
            ? recipes.OrderBy(r => r.PrepTimeMinutes).ToList()
            : recipes.OrderByDescending(r => r.Id).ToList();
    }

    private string GetSortUrl(string sort)
    {
        return Nav.GetUriWithQueryParameter("sort", sort);
    }

    private async Task CancelPendingLoadAsync()
    {
        if (_loadCts is not null)
        {
            await _loadCts.CancelAsync();
            _loadCts.Dispose();
            _loadCts = null;
        }
    }

    public void Dispose()
    {
        _loadCts?.Cancel();
        _loadCts?.Dispose();
        _loadCts = null;
    }
}

