+    {
+        var sort = string.Equals(Sort, "popular", StringComparison.OrdinalIgnoreCase) ? "popular" : "newest";
+
+        if (_loadedCuisineId == CuisineId && _recipes is not null)
+        {
+            // Cuisine unchanged — only re-sort if needed.
+            if (_sort != sort)
+            {
+                _sort = sort;
+                _displayedRecipes = ApplySort(_recipes, _sort);
+            }
+            return;
+        }
+
+        _sort = sort;
+        await LoadRecipesAsync(CuisineId);
+    }
+
+    private async Task LoadRecipesAsync(int cuisineId)
+    {
+        // Cancel any in-flight load.
+        await CancelPendingLoadAsync();
+
+        var cts = new CancellationTokenSource();
+        _loadCts = cts;
+
+        _isLoading = true;
+        _errorMessage = null;
+        StateHasChanged();
+
+        try
+        {
+            var result = await RecipeService.GetByCuisineAsync(cuisineId, cts.Token);
+
+            // Guard against a stale completion after cancellation.
+            if (cts.Token.IsCancellationRequested) return;
+
+            _recipes = result;
+            _displayedRecipes = ApplySort(result, _sort);
+            _loadedCuisineId = cuisineId;
+            _errorMessage = null;
+        }
+        catch (OperationCanceledException) when (cts.Token.IsCancellationRequested)
+        {
+            // Expected when the user switched cuisines or navigated away.
+        }
+        catch (TimeoutException ex)
+        {
+            Logger.LogError(ex, "Timeout loading recipes for cuisine {CuisineId}", cuisineId);
+            _errorMessage = "The request timed out. Please try again.";
+        }
+        catch (Exception ex)
+        {
+            Logger.LogError(ex, "Failed to load recipes for cuisine {CuisineId}", cuisineId);
+            _errorMessage = "Something went wrong while loading recipes. Please try again.";
+        }
+        finally
+        {
+            if (!cts.Token.IsCancellationRequested)
+            {
+                _isLoading = false;
+            }
+        }
+    }
+
+    private async Task RetryAsync()
+    {
+        await LoadRecipesAsync(CuisineId);
+    }
+
+    private static List<Recipe> ApplySort(List<Recipe> recipes, string sort)
+    {
+        return sort == "popular"
+            ? recipes.OrderBy(r => r.PrepTimeMinutes).ToList()
+            : recipes.OrderByDescending(r => r.Id).ToList();
+    }
+
+    private string GetSortUrl(string sort)
+    {
+        return Nav.GetUriWithQueryParameter("sort", sort);
+    }
+
+    private async Task CancelPendingLoadAsync()
+    {
+        if (_loadCts is not null)
+        {
+            await _loadCts.CancelAsync();
+            _loadCts.Dispose();
+            _loadCts = null;
+        }
+    }
+
+    public void Dispose()
+    {
+        _loadCts?.Cancel();
+        _loadCts?.Dispose();
+        _loadCts = null;
+    }
+}
